import type { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE_URL = 'https://api.example.com';
const TEST_GENERATE_URL = `${TEST_BASE_URL}/images/generate`;
const TEST_IMAGE_URL = `${TEST_BASE_URL}/image.png`;
const TEST_IMAGE_BINARY = Buffer.from('test-binary-content');

const prompt = 'A pixel art castle at sunset';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: { currentDate },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [TEST_GENERATE_URL]: {
      response: {
        type: 'json-value',
        body: {
          images: [
            {
              url: TEST_IMAGE_URL,
              width: 512,
              height: 512,
            },
          ],
        },
      },
    },
    [TEST_IMAGE_URL]: {
      response: {
        type: 'binary',
        body: TEST_IMAGE_BINARY,
      },
    },
  });

  describe('doGenerate', () => {
    it('should pass the correct parameters', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        size: '512x512',
        seed: 42,
      });
    });

    it('should omit size when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('size');
    });

    it('should pass style from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: 'retro' } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        size: '256x256',
        style: 'retro',
      });
    });

    it('should pass pixelDensity as pixel_density from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: '128x128',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { pixelDensity: 8 } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 2,
        size: '128x128',
        pixel_density: 8,
      });
    });

    it('should pass both style and pixelDensity from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: 7,
        providerOptions: { pixelart: { style: '8bit', pixelDensity: 4 } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        size: '512x512',
        seed: 7,
        style: '8bit',
        pixel_density: 4,
      });
    });

    it('should return downloaded images as Uint8Array', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      expect(result.images[0]).toStrictEqual(
        new Uint8Array(TEST_IMAGE_BINARY),
      );
    });

    it('should warn for unsupported aspectRatio', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'unsupported',
          feature: 'aspectRatio',
        }),
      );
    });

    it('should warn for unsupported files (image editing)', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: [{ type: 'url', url: 'https://example.com/img.png' }],
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'unsupported',
          feature: 'image editing',
        }),
      );
    });

    it('should warn for unsupported mask (inpainting)', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: { type: 'url', url: 'https://example.com/mask.png' },
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'unsupported',
          feature: 'inpainting',
        }),
      );
    });

    it('should return no warnings when all options are supported', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: 1,
        providerOptions: { pixelart: { style: 'pixel', pixelDensity: 2 } },
      });

      expect(result.warnings).toHaveLength(0);
    });

    it('should pass headers correctly', async () => {
      const model = createBasicModel({
        headers: {
          Authorization: 'Bearer test-key',
          'x-custom-provider': 'pixelart',
        },
      });

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: { 'x-request-id': 'req-123' },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer test-key',
        'x-custom-provider': 'pixelart',
        'x-request-id': 'req-123',
      });
    });

    it('should include response metadata', async () => {
      const testDate = new Date('2024-01-15T12:00:00.000Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.response).toMatchObject({
        modelId: 'pixelart-v1',
        timestamp: testDate,
      });
    });

    it('should handle API errors', async () => {
      server.urls[TEST_GENERATE_URL].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({ message: 'Invalid prompt: too short' }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt: 'x',
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        }),
      ).rejects.toThrow('Invalid prompt: too short');
    });
  });

  describe('provider properties', () => {
    it('should have the correct specificationVersion', () => {
      const model = createBasicModel();
      expect(model.specificationVersion).toBe('v3');
    });

    it('should have the correct provider', () => {
      const model = createBasicModel();
      expect(model.provider).toBe('pixelart.image');
    });

    it('should have the correct modelId', () => {
      const model = createBasicModel();
      expect(model.modelId).toBe('pixelart-v1');
    });

    it('should have the correct maxImagesPerCall', () => {
      const model = createBasicModel();
      expect(model.maxImagesPerCall).toBe(4);
    });
  });
});

